SmartRisk.Navbar={update(path){const c=SmartRisk.Config.navigation.find(i=>i.path===path),u=SmartRisk.Config.currentUser,e=document.getElementById("app-navbar");e.innerHTML=`<div class="navbar-left"><button id="navbar-menu" class="icon-btn">${SmartRisk.Icon.render("menu",20)}</button><div><h2 class="navbar-title">${c?.label||"SmartRisk"}</h2><div class="navbar-context">${SmartRisk.Utils.formatDate()}</div></div></div><div class="navbar-right"><button id="theme-toggle" class="icon-btn">${SmartRisk.Icon.render("moon",19)}</button><button class="icon-btn">${SmartRisk.Icon.render("bell",19)}</button><strong>${u.initials}</strong></div>`;document.getElementById("navbar-menu").onclick=SmartRisk.Sidebar.toggle;document.getElementById("theme-toggle").onclick=SmartRisk.Theme.toggle}};